using System.Collections.Generic;\nusing System.Linq;\nusing System.Threading.Tasks;\n\nnamespace HybridBusinessPOS.Core.Repositories\n{\n    public interface IRepository<T> where T : class\n    {\n        Task<T> GetByIdAsync(int id);\n        Task<IEnumerable<T>> GetAllAsync();\n        Task AddAsync(T entity);\n        void Update(T entity);\n        void Delete(T entity);\n    }\n\n    public class UnitOfWork : IUnitOfWork\n    {\n        private readonly ApplicationDbContext _context;\n        private IRepository<Product> _productRepository;\n        private IRepository<Customer> _customerRepository;\n        private IRepository<Order> _orderRepository;\n        private IRepository<Inventory> _inventoryRepository;\n        private IRepository<Supplier> _supplierRepository;\n        private IRepository<PurchaseOrder> _purchaseOrderRepository;\n        private IRepository<Invoice> _invoiceRepository;\n        private IRepository<Payment> _paymentRepository;\n\n        public UnitOfWork(ApplicationDbContext context)\n        {\n            _context = context;\n        }\n\n        public IRepository<Product> ProductRepository => _productRepository ??= new Repository<Product>(_context);\n        public IRepository<Customer> CustomerRepository => _customerRepository ??= new Repository<Customer>(_context);\n        public IRepository<Order> OrderRepository => _orderRepository ??= new Repository<Order>(_context);\n        public IRepository<Inventory> InventoryRepository => _inventoryRepository ??= new Repository<Inventory>(_context);\n        public IRepository<Supplier> SupplierRepository => _supplierRepository ??= new Repository<Supplier>(_context);\n        public IRepository<PurchaseOrder> PurchaseOrderRepository => _purchaseOrderRepository ??= new Repository<PurchaseOrder>(_context);\n        public IRepository<Invoice> InvoiceRepository => _invoiceRepository ??= new Repository<Invoice>(_context);\n        public IRepository<Payment> PaymentRepository => _paymentRepository ??= new Repository<Payment>(_context);\n\n        public async Task<int> SaveChangesAsync()\n        {\n            return await _context.SaveChangesAsync();\n        }\n    }\n\n    public class Repository<T> : IRepository<T> where T : class\n    {\n        private readonly ApplicationDbContext _context;\n        private readonly DbSet<T> _dbSet;\n\n        public Repository(ApplicationDbContext context)\n        {\n            _context = context;\n            _dbSet = _context.Set<T>();\n        }\n\n        public async Task<T> GetByIdAsync(int id)\n        {\n            return await _dbSet.FindAsync(id);\n        }\n\n        public async Task<IEnumerable<T>> GetAllAsync()\n        {\n            return await _dbSet.ToListAsync();\n        }\n\n        public async Task AddAsync(T entity)\n        {\n            await _dbSet.AddAsync(entity);\n        }\n\n        public void Update(T entity)\n        {\n            _dbSet.Update(entity);\n        }\n\n        public void Delete(T entity)\n        {\n            _dbSet.Remove(entity);\n        }\n    }\n}